using System;

// Deleqat təyini
public delegate void GreetHandler(string name);

class Greeter
{
    public void SayHello(string name)
    {
        Console.WriteLine($"Salam, {name}!");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Greeter greeter = new Greeter();
        // Deleqata metod təyin etmək
        GreetHandler greet = greeter.SayHello;
        // Deleqatı çağırmaq
        greet("Ali");
    }
}
// Output:
// Salam, Ali!

using System;

public delegate void MessageHandler(string message);

class Messenger
{
    public void SendEmail(string message)
    {
        Console.WriteLine($"E-poçt göndərildi: {message}");
    }

    public void SendSMS(string message)
    {
        Console.WriteLine($"SMS göndərildi: {message}");
    }
}

class Program
{
    static void Main(string[] args)
    {
        Messenger messenger = new Messenger();
        MessageHandler handler = messenger.SendEmail;
        handler += messenger.SendSMS; // İkinci metodu əlavə etmək

        // Deleqatı çağırmaq
        handler("Yeni mesaj var!");
    }
}
// Output:
// E-poçt göndərildi: Yeni mesaj var!
// SMS göndərildi: Yeni mesaj var!

using System;

public delegate void CalculateHandler(int number);

class Calculator
{
    public void Process(CalculateHandler calc)
    {
        calc(42);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Calculator calculator = new Calculator();

        // Anonim metod
        calculator.Process(delegate(int number) { Console.WriteLine($"Anonim metod: {number}"); });

        // Lambda ifadəsi
        calculator.Process(number => Console.WriteLine($"Lambda ifadəsi: {number}"));
    }
}
