using System;

public delegate void NotificationHandler(string message);

class Notifier
{
    public NotificationHandler OnNotify;

    public void SendNotification(string message)
    {
        OnNotify?.Invoke(message);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Notifier notifier = new Notifier();

        // Deleqata lambda ifadələri ilə metodlar əlavə etmək
        notifier.OnNotify += msg => Console.WriteLine($"Xəbərdarlıq: {msg}");
        notifier.OnNotify += msg => Console.WriteLine($"Jurnal: {msg}");

        // Bildiriş göndərmək
        notifier.SendNotification("Vacib yeniləmə!");

        // Bir deleqatı ləğv etmək
        notifier.OnNotify -= msg => Console.WriteLine($"Jurnal: {msg}");

        // Yenidən bildiriş göndərmək
        notifier.SendNotification("İkinci yeniləmə!");
    }
}
// Output:
// Xəbərdarlıq: Vacib yeniləmə!
// Jurnal: Vacib yeniləmə!
// Xəbərdarlıq: İkinci yeniləmə!

