public delegate void NotificationHandler(string message);

class Notifier
{
    public NotificationHandler OnNotify;

    public void SendNotification(string message)
    {
        OnNotify?.Invoke(message);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Notifier notifier = new Notifier();

        // Assign methods to delegate using lambda expressions
        notifier.OnNotify += msg => Console.WriteLine($"Notification: {msg}");
        notifier.OnNotify += msg => Console.WriteLine($"Log: {msg}");

        // Send notification
        notifier.SendNotification("Important update!");

        // Unsubscribe one delegate
        notifier.OnNotify -= msg => Console.WriteLine($"Log: {msg}");

        // Send another notification
        notifier.SendNotification("Second update!");
    }
}
// Output:
// Notification: Important update!
// Log: Important update!
// Notification: Second update!

