using System;

public delegate void NotificationHandler(string message);

class Notifier
{
    public NotificationHandler OnNotify;

    public void SendNotification(string message)
    {
        OnNotify?.Invoke(message);
    }
}

class Program
{
    static void Main(string[] args)
    {
        Notifier notifier = new Notifier();

        // Назначение методов делегату с помощью лямбда-выражений
        notifier.OnNotify += msg => Console.WriteLine($"Уведомление: {msg}");
        notifier.OnNotify += msg => Console.WriteLine($"Журнал: {msg}");

        // Отправка уведомления
        notifier.SendNotification("Важное обновление!");

        // Отписка одного делегата
        notifier.OnNotify -= msg => Console.WriteLine($"Журнал: {msg}");

        // Отправка другого уведомления
        notifier.SendNotification("Второе обновление!");
    }
}
// Output:
// Уведомление: Важное обновление!
// Журнал: Важное обновление!
// Уведомление: Второе обновление!
